function StockTracker() {
  const [symbol, setSymbol] = React.useState('REPLACE_WITH_SYMBOL');
  const [data, setData] = React.useState(null);
  const [loading, setLoading] = React.useState(false);

  React.useEffect(() => {
    if (!symbol) return;
    setLoading(true);
    fetch(`https://query1.finance.yahoo.com/v8/finance/chart/${symbol}?interval=1d&range=1mo`)
      .then(r => r.json())
      .then(d => {
        setData(d.chart?.result?.[0]); setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [symbol]);

  const prices = data?.indicators?.quote?.[0]?.close?.filter(Boolean) || [];
  const min = Math.min(...prices);
  const max = Math.max(...prices);
  const current = prices[prices.length - 1];
  const prev = prices[prices.length - 2];
  const change = current && prev ? ((current - prev) / prev * 100).toFixed(2) : '0.00';

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',gap:8,marginBottom:12}}>
        <input value={symbol} onChange={e=>setSymbol(e.target.value.toUpperCase())}
          style={{flex:1,padding:'8px 12px',borderRadius:8,border:'1px solid #ccc',fontSize:14}}
          placeholder="Enter ticker (e.g. AAPL)"/>
        <button onClick={()=>setSymbol(symbol)}
          style={{padding:'8px 16px',borderRadius:8,background:'#007AFF',color:'#fff',border:'none',cursor:'pointer'}}>
          Search
        </button>
      </div>
      {loading && <div style={{textAlign:'center',color:'#888'}}>Loading…</div>}
      {data && (
        <div style={{flex:1,display:'flex',flexDirection:'column'}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'baseline',marginBottom:12}}>
            <span style={{fontSize:24,fontWeight:700}}>${current?.toFixed(2)}</span>
            <span style={{fontSize:16,color:change>=0?'#34C759':'#FF3B30',fontWeight:600}}>
              {change>=0?'+':''}{change}%
            </span>
          </div>
          <div style={{flex:1,display:'flex',alignItems:'flex-end',gap:2}}>
            {prices.map((p,i)=>{
              const h = max===min?50:((p-min)/(max-min))*100;
              return (
                <div key={i} style={{flex:1,height:`${h}%`,background:i===prices.length-1?'#007AFF':'#007AFF40',borderRadius:2,minHeight:4}}/>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}
render(<StockTracker/>);
